	letter-spacing: 0 !important;
	color: var(--color-subtle) !important;
}

[data-footnotes] [data-streamdown="ordered-list"] {
	margin: 0 !important;
	padding-left: 1.25rem !important;
}

[data-footnotes] [data-streamdown="list-item"] {
	margin: 0.3rem 0 !important;
	padding: 0 !important;
}

